// src/hooks/useCheckout.js
import { useState, useEffect, useCallback } from 'react';
import useAuthStore from '../store/authStore';
import useCartStore from '../store/cartStore';

const SAVED_ADDRESSES_KEY = 'arkee_saved_addresses';

const useCheckout = () => {
  const { user } = useAuthStore();
  const { cart } = useCartStore();

  const [currentStep, setCurrentStep] = useState(0);
  const [selectedAddress, setSelectedAddress] = useState(null);
  const [savedAddresses, setSavedAddresses] = useState([]);
  const [paymentMethod, setPaymentMethod] = useState(null);
  const [paymentDetails, setPaymentDetails] = useState({});
  const [orderPlaced, setOrderPlaced] = useState(false);
  const [orderId, setOrderId] = useState(null);
  const [processing, setProcessing] = useState(false);

  // ── Load saved addresses from localStorage ──────────────────────────────
  useEffect(() => {
    try {
      const raw = localStorage.getItem(SAVED_ADDRESSES_KEY);
      if (raw) {
        const addresses = JSON.parse(raw);
        setSavedAddresses(addresses);

        // Auto-select the default address if one exists
        const defaultAddr = addresses.find((a) => a.isDefault);
        if (defaultAddr) setSelectedAddress(defaultAddr);
      }
    } catch {
      setSavedAddresses([]);
    }
  }, []);

  // ── Auto-fill user data from auth store ─────────────────────────────────
  // Matches the field names used in Register.jsx:
  //   firstname, lastname, email, mobile
  const getUserData = useCallback(
    () => ({
      // Individual name parts (as stored during registration)
      firstName: user?.firstname || '',
      lastName: user?.lastname || '',

      // Combined full name — tries dedicated fields first, then constructs
      // from firstname + lastname (matching the Register form fields)
      name:
        user?.name ||
        user?.fullName ||
        `${user?.firstname || ''} ${user?.lastname || ''}`.trim(),

      // Email — direct field from registration form
      email: user?.email || '',

      // Phone — Register uses 'mobile'; support legacy 'phone' fallback
      phone: user?.mobile || user?.phone || '',

      // Optional address fields pre-saved on the user profile
      address: user?.address || '',
      city: user?.city || '',
      state: user?.state || '',
      pincode: user?.pincode || '',
      country: user?.country || 'India',
    }),
    [user]
  );

  // ── Save a new address ───────────────────────────────────────────────────
  const saveAddress = useCallback(
    (address) => {
      const id = `addr_${Date.now()}_${Math.random()
        .toString(36)
        .slice(2, 7)}`;
      const newAddress = { ...address, id };

      let updated;
      if (newAddress.isDefault) {
        // Clear default flag on all existing addresses
        updated = savedAddresses.map((a) => ({ ...a, isDefault: false }));
        updated.push(newAddress);
      } else {
        updated = [...savedAddresses, newAddress];
      }

      setSavedAddresses(updated);
      localStorage.setItem(SAVED_ADDRESSES_KEY, JSON.stringify(updated));
      setSelectedAddress(newAddress);
      return newAddress;
    },
    [savedAddresses]
  );

  // ── Delete an address ────────────────────────────────────────────────────
  const deleteAddress = useCallback(
    (addressId) => {
      const updated = savedAddresses.filter((a) => a.id !== addressId);
      setSavedAddresses(updated);
      localStorage.setItem(SAVED_ADDRESSES_KEY, JSON.stringify(updated));

      // Deselect if the removed address was selected
      if (selectedAddress?.id === addressId) {
        setSelectedAddress(null);
      }
    },
    [savedAddresses, selectedAddress]
  );

  // ── Set an address as default ────────────────────────────────────────────
  const setDefaultAddress = useCallback(
    (addressId) => {
      const updated = savedAddresses.map((a) => ({
        ...a,
        isDefault: a.id === addressId,
      }));
      setSavedAddresses(updated);
      localStorage.setItem(SAVED_ADDRESSES_KEY, JSON.stringify(updated));
    },
    [savedAddresses]
  );

  // ── Edit an existing address ─────────────────────────────────────────────
  const editAddress = useCallback(
    (addressId, updatedData) => {
      const updated = savedAddresses.map((a) =>
        a.id === addressId ? { ...a, ...updatedData } : a
      );
      setSavedAddresses(updated);
      localStorage.setItem(SAVED_ADDRESSES_KEY, JSON.stringify(updated));

      // Keep selectedAddress in sync
      if (selectedAddress?.id === addressId) {
        setSelectedAddress((prev) => ({ ...prev, ...updatedData }));
      }
    },
    [savedAddresses, selectedAddress]
  );

  // ── Price calculations ───────────────────────────────────────────────────
  const cartItems = cart || [];

  const subtotal = cartItems.reduce((sum, item) => {
    const price =
      item.productId?.discountPrice ||
      item.productId?.price ||
      item.price ||
      0;
    return sum + price * (item.quantity || 1);
  }, 0);

  const shippingCharge = subtotal >= 999 ? 0 : 99;
  const tax = Math.round(subtotal * 0.03); // 3% GST
  const total = subtotal + shippingCharge + tax;

  // ── Step navigation ──────────────────────────────────────────────────────
  const nextStep = () => setCurrentStep((s) => Math.min(s + 1, 2));
  const prevStep = () => setCurrentStep((s) => Math.max(s - 1, 0));
  const goToStep = (step) => setCurrentStep(step);

  // ── Place order ──────────────────────────────────────────────────────────
  const placeOrder = useCallback(async () => {
    setProcessing(true);
    try {
      // Simulate payment gateway processing (replace with real API call)
      await new Promise((r) => setTimeout(r, 3000));

      // Generate a unique order ID
      const oid = `ARK${Date.now().toString(36).toUpperCase()}${Math.random()
        .toString(36)
        .slice(2, 6)
        .toUpperCase()}`;

      setOrderId(oid);
      setOrderPlaced(true);
      return oid;
    } finally {
      setProcessing(false);
    }
  }, []);

  return {
    // Step state
    currentStep,
    setCurrentStep,
    nextStep,
    prevStep,
    goToStep,

    // Address state
    selectedAddress,
    setSelectedAddress,
    savedAddresses,
    saveAddress,
    deleteAddress,
    setDefaultAddress,
    editAddress,

    // Payment state
    paymentMethod,
    setPaymentMethod,
    paymentDetails,
    setPaymentDetails,

    // Order state
    orderPlaced,
    orderId,
    processing,
    placeOrder,

    // User data (auto-filled from auth store, field names match Register.jsx)
    getUserData,

    // Pricing
    subtotal,
    shippingCharge,
    tax,
    total,
    cartItems,
  };
};

export default useCheckout;