// src/pages/Checkout.jsx
import React, { useEffect, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  MapPinIcon,
  CreditCardIcon,
  ClipboardDocumentCheckIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  LockClosedIcon,
} from '@heroicons/react/24/outline';
import useCheckout from '../hooks/useCheckout';
import useAuthStore from '../store/authStore';
import AddressStep from '../components/checkout/AddressStep';
import PaymentStep from '../components/checkout/PaymentStep';
import ReviewStep from '../components/checkout/ReviewStep';
import OrderSuccess from '../components/checkout/OrderSuccess';
import toast from 'react-hot-toast';

const STEPS = [
  { id: 0, label: 'Address', icon: MapPinIcon, shortLabel: 'Address' },
  { id: 1, label: 'Payment', icon: CreditCardIcon, shortLabel: 'Payment' },
  {
    id: 2,
    label: 'Review',
    icon: ClipboardDocumentCheckIcon,
    shortLabel: 'Review',
  },
];

const Checkout = () => {
  const navigate = useNavigate();
  const { user } = useAuthStore();

  const {
    currentStep,
    selectedAddress,
    setSelectedAddress,
    savedAddresses,
    paymentMethod,
    setPaymentMethod,
    paymentDetails,
    setPaymentDetails,
    orderPlaced,
    orderId,
    processing,
    getUserData,
    saveAddress,
    deleteAddress,
    setDefaultAddress,
    editAddress,
    subtotal,
    shippingCharge,
    tax,
    total,
    cartItems,
    nextStep,
    prevStep,
    goToStep,
    placeOrder,
  } = useCheckout();

  const userData = useMemo(() => getUserData(), [getUserData]);

  // Redirect if cart is empty
  useEffect(() => {
    if (!cartItems || cartItems.length === 0) {
      // toast.error('Your cart is empty!');
      // navigate('/cart');
    }
  }, [cartItems, navigate]);

  // Handle place order
  const handlePlaceOrder = async () => {
    try {
      await placeOrder();
      toast.success('Order placed successfully! 🎉');
    } catch {
      toast.error('Failed to place order. Please try again.');
    }
  };

  // Order Success Screen
  if (orderPlaced) {
    return (
      <OrderSuccess
        orderId={orderId}
        email={userData.email}
        total={total + (paymentDetails?.method === 'cod' ? 40 : 0)}
      />
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-cream-50 via-white to-rose-50/30">
      {/* Top Bar */}
      <div className="bg-white border-b border-gray-100 sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between py-4">
            <div className="flex items-center gap-3">
              <button
                onClick={() =>
                  currentStep === 0 ? navigate('/cart') : prevStep()
                }
                className="p-2 rounded-xl hover:bg-gray-100 transition-colors"
              >
                <ChevronLeftIcon className="w-5 h-5 text-gray-600" />
              </button>
              <div>
                <h1 className="font-serif text-xl font-bold text-gray-800">
                  Checkout
                </h1>
                {userData.name && (
                  <p className="text-xs text-gray-400">
                    Hello, {userData.name} 👋
                  </p>
                )}
              </div>
            </div>

            {/* Security Badge */}
            <div className="hidden sm:flex items-center gap-2 text-green-600">
              <LockClosedIcon className="w-4 h-4" />
              <span className="text-xs font-medium">
                100% Secure Checkout
              </span>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* ── Step Progress Bar ── */}
        <div className="mb-8">
          <div className="flex items-center justify-between max-w-lg mx-auto">
            {STEPS.map((step, index) => {
              const isActive = currentStep === step.id;
              const isCompleted = currentStep > step.id;
              const StepIcon = step.icon;

              return (
                <React.Fragment key={step.id}>
                  {/* Step Circle */}
                  <button
                    onClick={() => {
                      if (isCompleted) goToStep(step.id);
                    }}
                    disabled={!isCompleted && !isActive}
                    className={`flex flex-col items-center gap-2 group transition-all ${
                      isCompleted ? 'cursor-pointer' : ''
                    }`}
                  >
                    <div
                      className={`relative w-12 h-12 rounded-2xl flex items-center justify-center transition-all duration-500 ${
                        isActive
                          ? 'bg-gradient-to-br from-rose-500 to-pink-500 shadow-lg shadow-rose-200 scale-110'
                          : isCompleted
                            ? 'bg-green-500 shadow-lg shadow-green-200'
                            : 'bg-gray-200'
                      }`}
                    >
                      {isCompleted ? (
                        <svg
                          className="w-6 h-6 text-white"
                          viewBox="0 0 24 24"
                          fill="none"
                          stroke="currentColor"
                          strokeWidth="3"
                        >
                          <path d="M5 13l4 4L19 7" />
                        </svg>
                      ) : (
                        <StepIcon
                          className={`w-5 h-5 ${
                            isActive ? 'text-white' : 'text-gray-500'
                          }`}
                        />
                      )}

                      {/* Pulse effect for active */}
                      {isActive && (
                        <div className="absolute inset-0 rounded-2xl bg-rose-400 animate-ping opacity-20" />
                      )}
                    </div>

                    <span
                      className={`text-xs font-semibold transition-colors ${
                        isActive
                          ? 'text-rose-500'
                          : isCompleted
                            ? 'text-green-600'
                            : 'text-gray-400'
                      }`}
                    >
                      {step.shortLabel}
                    </span>
                  </button>

                  {/* Connector Line */}
                  {index < STEPS.length - 1 && (
                    <div className="flex-1 mx-3 mb-6">
                      <div className="h-1 bg-gray-200 rounded-full overflow-hidden">
                        <div
                          className={`h-full rounded-full transition-all duration-700 ease-out ${
                            currentStep > index
                              ? 'bg-gradient-to-r from-green-400 to-green-500 w-full'
                              : currentStep === index
                                ? 'bg-gradient-to-r from-rose-400 to-rose-300 w-1/2'
                                : 'w-0'
                          }`}
                        />
                      </div>
                    </div>
                  )}
                </React.Fragment>
              );
            })}
          </div>
        </div>

        {/* ── Main Content ── */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left - Step Content */}
          <div className="lg:col-span-2">
            {currentStep === 0 && (
              <AddressStep
                savedAddresses={savedAddresses}
                selectedAddress={selectedAddress}
                onSelectAddress={setSelectedAddress}
                onSaveAddress={saveAddress}
                onDeleteAddress={deleteAddress}
                onSetDefault={setDefaultAddress}
                onEditAddress={editAddress}
                userData={userData}
                onNext={nextStep}
              />
            )}

            {currentStep === 1 && (
              <PaymentStep
                paymentMethod={paymentMethod}
                setPaymentMethod={setPaymentMethod}
                paymentDetails={paymentDetails}
                setPaymentDetails={setPaymentDetails}
                onNext={nextStep}
                onBack={prevStep}
                total={total}
              />
            )}

            {currentStep === 2 && (
              <ReviewStep
                selectedAddress={selectedAddress}
                paymentDetails={paymentDetails}
                cartItems={cartItems}
                subtotal={subtotal}
                shippingCharge={shippingCharge}
                tax={tax}
                total={total}
                onBack={prevStep}
                onPlaceOrder={handlePlaceOrder}
                processing={processing}
              />
            )}
          </div>

          {/* Right - Order Summary Sidebar */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm sticky top-24">
              <h2 className="font-serif text-lg font-bold text-gray-800 mb-5 pb-4 border-b border-gray-100">
                Order Summary
              </h2>

              {/* Cart Items Mini */}
              <div className="space-y-3 mb-5 max-h-48 overflow-y-auto">
                {cartItems.map((item, idx) => {
                  const product = item.productId || item.product || item;
                  const name = product?.name || 'Product';
                  const image =
                    product?.images?.[0] ||
                    'https://placehold.co/60x60/fce7f3/be185d?text=A';
                  const price =
                    product?.discountPrice ||
                    product?.price ||
                    item.price ||
                    0;
                  const qty = item.quantity || 1;

                  return (
                    <div
                      key={idx}
                      className="flex items-center gap-3"
                    >
                      <div className="relative flex-shrink-0">
                        <img
                          src={image}
                          alt={name}
                          className="w-12 h-12 rounded-lg object-cover border border-gray-200"
                        />
                        <span className="absolute -top-1.5 -right-1.5 w-5 h-5 rounded-full bg-gray-800 text-white text-[10px] flex items-center justify-center font-bold">
                          {qty}
                        </span>
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-xs font-medium text-gray-700 line-clamp-1">
                          {name}
                        </p>
                      </div>
                      <p className="text-xs font-semibold text-gray-800">
                        ₹{(price * qty).toLocaleString()}
                      </p>
                    </div>
                  );
                })}
              </div>

              {/* Price Breakdown */}
              <div className="space-y-2.5 pt-4 border-t border-gray-100">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">Subtotal</span>
                  <span className="text-gray-700 font-medium">
                    ₹{subtotal.toLocaleString()}
                  </span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">Shipping</span>
                  <span
                    className={`font-medium ${
                      shippingCharge === 0
                        ? 'text-green-600'
                        : 'text-gray-700'
                    }`}
                  >
                    {shippingCharge === 0 ? 'FREE' : `₹${shippingCharge}`}
                  </span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">Tax (3% GST)</span>
                  <span className="text-gray-700 font-medium">
                    ₹{tax.toLocaleString()}
                  </span>
                </div>
                {paymentMethod === 'cod' && (
                  <div className="flex justify-between text-sm">
                    <span className="text-amber-600">COD Charge</span>
                    <span className="text-amber-600 font-medium">₹40</span>
                  </div>
                )}
              </div>

              <div className="border-t-2 border-dashed border-gray-100 mt-4 pt-4">
                <div className="flex justify-between items-center">
                  <span className="font-bold text-gray-800">Total</span>
                  <span className="font-bold text-gray-900 text-xl">
                    ₹
                    {(
                      total + (paymentMethod === 'cod' ? 40 : 0)
                    ).toLocaleString()}
                  </span>
                </div>
              </div>

              {/* Trust signals */}
              <div className="mt-5 pt-5 border-t border-gray-100 space-y-3">
                {[
                  {
                    emoji: '🔒',
                    text: '256-bit SSL Encryption',
                    sub: 'Bank-level security',
                  },
                  {
                    emoji: '📦',
                    text: 'Free Returns',
                    sub: '7-day easy return',
                  },
                  {
                    emoji: '💎',
                    text: 'Authenticity Guaranteed',
                    sub: 'Certified jewellery',
                  },
                ].map((item) => (
                  <div
                    key={item.text}
                    className="flex items-center gap-3"
                  >
                    <span className="text-lg">{item.emoji}</span>
                    <div>
                      <p className="text-xs font-semibold text-gray-700">
                        {item.text}
                      </p>
                      <p className="text-[10px] text-gray-400">
                        {item.sub}
                      </p>
                    </div>
                  </div>
                ))}
              </div>

              {/* Need help */}
              <div className="mt-5 pt-4 border-t border-gray-100 text-center">
                <p className="text-xs text-gray-400">Need help?</p>
                <Link
                  to="/contact"
                  className="text-xs text-rose-500 hover:text-rose-600 font-medium"
                >
                  Contact Support →
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Custom CSS for animations */}
      <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes slide-up {
          from { opacity: 0; transform: translateY(20px) scale(0.98); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        @keyframes slide-down {
          from { opacity: 0; max-height: 0; }
          to { opacity: 1; max-height: 1000px; }
        }
        @keyframes scale-in {
          from { transform: scale(0); }
          to { transform: scale(1); }
        }
        @keyframes bounce-once {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.2); }
        }
        @keyframes draw-check {
          from { stroke-dashoffset: 24; }
          to { stroke-dashoffset: 0; }
        }
        .animate-fade-in {
          animation: fade-in 0.4s ease-out;
        }
        .animate-slide-up {
          animation: slide-up 0.5s cubic-bezier(0.16, 1, 0.3, 1);
        }
        .animate-slide-down {
          animation: slide-down 0.4s ease-out;
          overflow: hidden;
        }
        .animate-scale-in {
          animation: scale-in 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        }
        .animate-bounce-once {
          animation: bounce-once 0.5s ease-out;
        }
        .animate-draw-check path {
          stroke-dasharray: 24;
          animation: draw-check 0.6s ease-out 0.3s forwards;
          stroke-dashoffset: 24;
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 4px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #e5e7eb;
          border-radius: 999px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #d1d5db;
        }
      `}</style>
    </div>
  );
};

export default Checkout;